}

// --------------------
// parallel "machine id" (Voltronic parallel ID) != inverterNum
// --------------------
let machine = flow.get(`inv${inverterNum}_parallel_id`);
if (machine === undefined || machine === null || machine === "") machine = 0;
machine = Number(machine);
if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;

let cmd = null;

// =====================
// SELECTS
// =====================
if (param === "output_source_priority") {
  const sv = String(v).trim();

  const map = {
    // modern
    UtilitySolarBat: "POP00",
    SolarUtilityBat: "POP01",
    SolarBatUtility: "POP02",

    // legacy
    USB: "POP00",
    SUB: "POP01",
    SBU: "POP02"
  };

  cmd = map[sv] || null;

} else if (param === "charger_source_priority") {
  const sv = String(v).trim();

  const map = {
    // modern
    "Solar first": "PCP01",
    "Solar + Utility": "PCP02",
    "Only solar": "PCP03",

    // legacy
    CSO: "PCP01",
    SNU: "PCP02",
    OSO: "PCP03"
  };

  cmd = map[sv] || null;

} else if (param === "battery_type") {
  const map = {
    AGM: "PBT00",
    Flooded: "PBT01",
    User: "PBT02",
    Pylon: "PBT03",
    Weco: "PBT05",
    Soltaro: "PBT06",
    Lib: "PBT08",
    Lic: "PBT09"
  };
  cmd = map[String(v)] || null;
}

// =====================
// VOLTAGES nn.n
// =====================
else if (param === "battery_recharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCV${fixed1(nv)}`;

} else if (param === "battery_re_discharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDV${fixed1(nv)}`;

} else if (param === "battery_under_voltage") {
  const nv = toNum(v); if (nv == null) return null;
