  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function clearPublishedTopics() {
  const topics = flow.get(topicsKey) || [];
  if (!Array.isArray(topics) || topics.length === 0) return [];
  return topics.map(t => ({ topic: t, payload: "", retain: true }));
}

// =======================
// Si cet onduleur n'est pas activé
// =======================
if (!enabled) {
  let msgs = [];
  if (changed) {
    msgs = clearPublishedTopics();
    flow.set(topicsKey, []);
    flow.set(lastSigKey, signature);
  }
  return [msgs];
}

