  global.get("config.batterySystemVoltage") ||
  global.get("battery_system_voltage") ||
  48
);
const is24 = (sysV === 24);

// Voltage ranges depending on system
const V_RANGES = is24 ? {
  bulk: { min: 24, max: 30, step: 0.1 },
