const enabledInvs = Array.isArray(global.get("config.invertersList"))
  ? global.get("config.invertersList").map(Number).filter(n => [1, 2, 3].includes(n))
  : [];

const cfg = invCfgAll[inv] || {};
const enabled = enabledInvs.includes(inv);

// display mode
const displayMode = String(
  global.get(`inverter_${inv}.display_mode`) ||
  cfg.displayMode ||
  "modern"
).trim();

// signature de config pour ce discovery
const signature = JSON.stringify({
  enabled,
  transport: cfg.transport || "",
  serialPort: cfg.serialPort || "",
  gwHost: cfg.gwHost || "",
  gwPort: cfg.gwPort || "",
  batterySystemVoltage: sysV,
  displayMode
});

const lastSigKey = `inv${inv}_discovery_signature`;
const topicsKey = `inv${inv}_discovery_topics`;
const lastSig = flow.get(lastSigKey);
const changed = (lastSig !== signature);

