  return { topic, payload: JSON.stringify(payload), retain: true };
}

function numberCfg(objectId, name, unit, min, max, step, valueTpl, commandTopic, extra = {}) {
  const uid = `voltronic_${inv}_${objectId}`;
  const topic = `${HA_PREFIX}/number/${uid}/config`;

  const payload = {
    name,
    unique_id: uid,
    state_topic,
