  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function textCfg(objectId, name, commandTopic, extra = {}) {
  const uid = `voltronic_${inv}_${objectId}`;
  const topic = `${HA_PREFIX}/text/${uid}/config`;

  const payload = {
