// Compatible serial + gateway/tcp
//
// A CHANGER SELON LE NOEUD :
//   const inv = 1;   -> onduleur 1
//   const inv = 2;   -> onduleur 2
//   const inv = 3;   -> onduleur 3
// =======================

const inv = 3; // <-- CHANGER ICI : 1 / 2 / 3

const HA_PREFIX = "homeassistant";
const BASE_TOPIC = "voltronic";

// =======================
// Battery system voltage (24/48)
// =======================
const sysV = Number(
  global.get("config.batterySystemVoltage") ||
  global.get("battery_system_voltage") ||
  48
);
const is24 = (sysV === 24);

// Voltage ranges depending on system
const V_RANGES = is24 ? {
  bulk: { min: 24, max: 30, step: 0.1 },
  float: { min: 24, max: 30, step: 0.1 },
  returnGrid: { min: 22, max: 25.5, step: 0.5 },
  reDischarge: { min: 24, max: 29, step: 0.5 },
  under: { min: 20, max: 27, step: 0.5 },
} : {
  bulk: { min: 40, max: 65, step: 0.1 },
  float: { min: 40, max: 65, step: 0.1 },
  returnGrid: { min: 40, max: 65, step: 0.1 },
  reDischarge: { min: 40, max: 65, step: 0.1 },
  under: { min: 40, max: 65, step: 0.1 },
